try {
    global.set("mid", 0);
    node.status({ fill: "green", shape: "dot", text: "MID set" });
} catch (error) {
    node.error("Failed to set MID: " + error.message, error);
    node.status({ fill: "red", shape: "ring", text: "Failed to set MID" });
}

// === CONFIG ===
const MAX_BUFFER_MS = 24 * 60 * 60 * 1000; // 24u
const EVENT_ID = 9800;
const EVENT_SEV = 2;
const GATEWAY_DEV = "GATEWAY_ASSET_ID";

const buffering = global.get("Buffering") === true;
const prevBuffering = global.get("BufferingPrev") === true;
const bufferStartIso = global.get("BufferStart");

function getStartMs() {
    if (!bufferStartIso) return null;
    const t = new Date(bufferStartIso).getTime();
    return Number.isFinite(t) ? t : null;
}

function makeGatewayEvent(text) {
    const nowIso = new Date().toISOString();
    let mid = global.get("mid") || 0;
    global.set("mid", mid + 1);
    return { MID: mid, D: [{ Dev: GATEWAY_DEV, TS: nowIso, ED: [{ Id: EVENT_ID, Val: text, Sev: EVENT_SEV }], MD: [] }] };
}

function formatDuration(ms) {
    const s = Math.max(0, Math.floor(ms / 1000));
    const hh = Math.floor(s / 3600);
    const mm = Math.floor((s % 3600) / 60);
    const ss = s % 60;
    return `${hh}h ${mm}m ${ss}s`;
}

if (buffering && !prevBuffering) {
    const nowIso = new Date().toISOString();
    global.set("BufferStart", nowIso);
    global.set("BufferOverflow", false);
    global.set("BufferOverflowNotified", false);
    let backup = global.get("BackupData");
    if (!Array.isArray(backup)) backup = [];
    backup.unshift(makeGatewayEvent(`Buffering started on: ${nowIso}`));
    global.set("BackupData", backup);
}

if (!buffering && prevBuffering) {
    let backup = global.get("BackupData");
    if (!Array.isArray(backup)) backup = [];
    if (backup.length > 0) {
        const nowIso = new Date().toISOString();
        const startMs = getStartMs();
        const downMs = (startMs !== null) ? (Date.now() - startMs) : null;
        const downTxt = (downMs !== null) ? ` (downtime: ${formatDuration(downMs)})` : "";
        backup.push(makeGatewayEvent(`Buffering stopped and reconnected on: ${nowIso}${downTxt}`));
        const out2 = { payload: backup, topic: "BackupFlush", flushTs: nowIso };
        global.set("BackupData", []);
        global.set("BufferOverflow", false);
        global.set("BufferOverflowNotified", false);
        global.set("BufferStart", null);
        node.status({ fill: "green", shape: "dot", text: `Flushed ${backup.length} items` });
        global.set("BufferingPrev", buffering);
        return [msg, out2];
    } else {
        node.status({ fill: "green", shape: "dot", text: "No backup to flush" });
    }
}

if (buffering) {
    let startMs = getStartMs();
    if (startMs === null) {
        const nowIso = new Date().toISOString();
        global.set("BufferStart", nowIso);
        startMs = Date.now();
        global.set("BufferOverflow", false);
        global.set("BufferOverflowNotified", false);
    }
    const elapsed = Date.now() - startMs;
    if (elapsed > MAX_BUFFER_MS) {
        global.set("BufferOverflow", true);
        const overflowNotified = global.get("BufferOverflowNotified") === true;
        if (!overflowNotified) {
            const nowIso = new Date().toISOString();
            let backup = global.get("BackupData");
            if (!Array.isArray(backup)) backup = [];
            backup.push(makeGatewayEvent(`Buffering stopped because time exceeded: ${nowIso}`));
            global.set("BackupData", backup);
            global.set("BufferOverflowNotified", true);
            node.status({ fill: "red", shape: "ring", text: `BUFFER >24h - capture STOPPED` });
        } else {
            node.status({ fill: "red", shape: "ring", text: "BUFFER >24h - capture STOPPED" });
        }
        global.set("BufferingPrev", buffering);
        return [msg, null];
    }
    let backup = global.get("BackupData");
    if (!Array.isArray(backup)) backup = [];
    backup.push(msg.payload);
    global.set("BackupData", backup);
    const mins = Math.floor(elapsed / 60000);
    node.status({ fill: "yellow", shape: "dot", text: `Buffering: ${backup.length} items (${mins}m)` });
    global.set("BufferingPrev", buffering);
    return [msg, null];
}

node.status({ fill: "green", shape: "dot", text: "Realtime" });
global.set("BufferingPrev", buffering);
return [msg, null];

if (msg.status && msg.status.fill) {
    let currentBuffering = global.get("Buffering") || false;
    let newBuffering = currentBuffering;
    if (msg.status.fill === "green") { newBuffering = false; }
    else if (msg.status.fill === "yellow" || msg.status.fill === "red") { newBuffering = true; }
    if (newBuffering !== currentBuffering) {
        global.set("Buffering", newBuffering);
        if (newBuffering === true) {
            let now = new Date().toISOString();
            global.set("BufferStart", now);
            node.status({ fill: "yellow", shape: "ring", text: "Buffering ON" });
        } else {
            global.set("BufferStart", null);
            node.status({ fill: "green", shape: "dot", text: "Buffering OFF" });
        }
    }
}
return null;

let mid = global.get("mid") || 0;

const Dev = "GATEWAY_ASSET_ID";

const nowIso = new Date().toISOString();

msg.payload = {
    MID: mid,
    D: [{
        Dev: Dev,
        TS: nowIso,
        ED: [{
            Id: 9800,
            Val: `Node-RED deployed op: ${nowIso}`,
            Sev: 2
        }],
        MD: []
    }]
};

global.set("mid", mid + 1);
return msg;
